// Manual implementation when default would work
class Point {
    int x, y;
public:
    // Noncompliant: manual implementation when default would work
    bool operator==(const Point& other) const {
        return x == other.x && y == other.y;
    }

    // Noncompliant: manual implementation of three-way comparison
    std::strong_ordering operator<=>(const Point& other) const {
        if (x < other.x) return std::strong_ordering::less;
        if (x > other.x) return std::strong_ordering::greater;
        if (y < other.y) return std::strong_ordering::less;
        if (y > other.y) return std::strong_ordering::greater;
        return std::strong_ordering::equal;
    }
};

