compliant:
// Use defaulted operators when possible
class Point {
    int x, y;
public:
    // Compliant: let compiler generate optimal comparison
    bool operator==(const Point& other) const = default;

    // Compliant: defaulted three-way comparison
    std::strong_ordering operator<=>(const Point& other) const = default;
};

struct SimpleData {
    std::string name;
    int value;

    // Compliant: defaulted comparison
    bool operator==(const SimpleData& other) const = default;
    auto operator<=>(const SimpleData& other) const = default;
};

// When custom logic is needed - then manual implementation is justified
class Person {
    std::string firstName;
    std::string lastName;
    int age;

public:
    // Compliant: custom comparison logic needed
    bool operator==(const Person& other) const {
        // Case-insensitive name comparison
        return std::equal(firstName.begin(), firstName.end(),
                         other.firstName.begin(), other.firstName.end(),
                         [](char a, char b) { return std::tolower(a) == std::tolower(b); }) &&
               std::equal(lastName.begin(), lastName.end(),
                         other.lastName.begin(), other.lastName.end(),
                         [](char a, char b) { return std::tolower(a) == std::tolower(b); });
    }
};
